<template>
	<NcHeaderMenu
		v-if="!shutdown"
		id="notifications"
		v-model:open="open"
		class="notifications-button"
		:excludeClickOutsideSelectors="['.popover']"
		:aria-label="t('notifications', 'Notifications')"
		:title="t('notifications', 'Notifications')"
		@opened="onOpen">
		<template #trigger>
			<IconNotification
				:size="20"
				:count="isDnd ? 0 : notifications.length"
				:showDot="!isDnd && (notifications.length !== 0 || webNotificationsGranted === null)"
				:showWarning="hasThrottledPushNotifications" />
		</template>

		<!-- Notifications list content -->
		<div class="notification-container">
			<!-- Panel header with Do Not Disturb toggle -->
			<div class="notification-panel-header">
				<span class="notification-panel-title">{{ t('notifications', 'Notifications') }}</span>
				<NcButton
					variant="tertiary"
					:class="{ 'dnd-active': isDnd }"
					:title="isDnd ? t('notifications', 'Disable Do Not Disturb') : t('notifications', 'Enable Do Not Disturb')"
					:aria-label="isDnd ? t('notifications', 'Disable Do Not Disturb') : t('notifications', 'Enable Do Not Disturb')"
					@click="toggleDnd">
					<template #icon>
						<IconBellOff :size="18" />
					</template>
				</NcButton>
			</div>
			<!-- "New while DND" banner -->
			<div v-if="dndBanner > 0" class="notification-dnd-banner">
				<span>{{ dndBannerText }}</span>
				<NcButton variant="tertiary" @click="dndBanner = 0">
					<template #icon><IconClose :size="16" /></template>
				</NcButton>
			</div>
			<!-- Filter tabs: only shown when notifications span 3+ categories -->
			<div v-if="showFilterTabs" class="notification-filter-tabs" role="tablist">
				<button
					v-for="tab in filterTabs"
					:key="tab.id"
					role="tab"
					:aria-selected="activeFilter === tab.id"
					:class="['notification-filter-tab', { 'notification-filter-tab--active': activeFilter === tab.id }]"
					@click="activeFilter = tab.id">
					{{ tab.label }}
					<span v-if="tab.count" class="notification-filter-count">{{ tab.count }}</span>
				</button>
			</div>

			<transition name="fade" mode="out-in">
				<ul v-if="notificationGroups.length > 0" class="notification-wrapper">
					<NotificationItem
						v-if="hasThrottledPushNotifications"
						:notification="fairUsePolicyNotification" />
					<template v-for="(group, groupIdx) in notificationGroups" :key="group.app">
						<!-- Group header: only shown when there are multiple apps -->
						<li
							v-if="notificationGroups.length > 1"
							class="notification-group-header"
							role="button"
							tabindex="0"
							@click="toggleGroup(group.app)"
							@keydown.enter="toggleGroup(group.app)"
							@keydown.space.prevent="toggleGroup(group.app)">
							<span class="notification-group-name">{{ formatAppName(group.app) }}</span>
							<span class="notification-group-badge">{{ group.items.length }}</span>
							<IconChevronDown
								:size="14"
								:class="{ 'notification-group-chevron--collapsed': collapsedGroups.has(group.app) }" />
						</li>
						<NotificationItem
							v-for="(notification, itemIdx) in group.items"
							v-show="!collapsedGroups.has(group.app)"
							:key="`${notification.notificationId}-${activeFilter}`"
							:style="{ '--anim-index': visibleIndex(groupIdx, itemIdx) }"
							:class="{ 'notification--new': notification.notificationId > lastOpenMaxId, 'notification--collapsing': collapsingIds.has(notification.notificationId) }"
							:notification="notification"
							@remove="onRemove(notification)"
							@dismiss="onDismiss"
							@snooze="onSnooze" />
					</template>
				</ul>

				<!-- No notifications -->
				<NcEmptyContent
					v-else
					:name="emptyContentMessage"
					:description="emptyContentDescription">
					<template #icon>
						<div v-if="showInboxZero && !hasThrottledPushNotifications" class="inbox-zero-celebrate">
							<span v-for="i in 8" :key="i" class="confetti-dot" :style="`--confetti-i: ${i - 1}`" />
							<svg class="inbox-zero-check" viewBox="0 0 52 52" xmlns="http://www.w3.org/2000/svg">
								<circle class="inbox-zero-circle" cx="26" cy="26" r="22" />
								<polyline class="inbox-zero-checkmark" points="14,26 22,34 38,18" />
							</svg>
						</div>
						<IconBellOutline v-else-if="!hasThrottledPushNotifications" />
						<span v-else class="icon icon-alert-outline" />
					</template>

					<template v-if="hasThrottledPushNotifications" #action>
						<NcButton
							variant="primary"
							href="https://nextcloud.com/fairusepolicy"
							target="_blank"
							rel="noreferrer noopener">
							<template #icon>
								<IconMessageOutline :size="20" />
							</template>
							{{ t('notifications', 'Contact Nextcloud GmbH') }} ↗
						</NcButton>
					</template>
				</NcEmptyContent>
			</transition>

			<!-- Undo dismiss bar -->
			<transition name="fade">
				<div v-if="pendingUndo" class="notification-undo-bar">
					<span>{{ t('notifications', 'Notification dismissed') }}</span>
					<NcButton variant="tertiary" @click="onUndoDismiss">
						{{ t('notifications', 'Undo') }}
					</NcButton>
				</div>
			</transition>

			<!-- Dismiss all -->
			<div v-if="notifications.length > 0" class="dismiss-all">
				<NcButton
					variant="tertiary"
					wide
					@click="onDismissAll">
					<template #icon>
						<IconClose :size="20" />
					</template>
					{{ t('notifications', 'Dismiss all notifications') }}
				</NcButton>
			</div>
		</div>
	</NcHeaderMenu>
</template>

<script>
import { getCurrentUser, getRequestToken } from '@nextcloud/auth'
import axios from '@nextcloud/axios'
import { getCapabilities } from '@nextcloud/capabilities'
import { showError } from '@nextcloud/dialogs'
import { emit, subscribe, unsubscribe } from '@nextcloud/event-bus'
import { loadState } from '@nextcloud/initial-state'
import { t } from '@nextcloud/l10n'
import { listen } from '@nextcloud/notify_push'
import { generateOcsUrl, imagePath } from '@nextcloud/router'
import NcButton from '@nextcloud/vue/components/NcButton'
import NcEmptyContent from '@nextcloud/vue/components/NcEmptyContent'
import NcHeaderMenu from '@nextcloud/vue/components/NcHeaderMenu'
import IconBellOff from 'vue-material-design-icons/BellOff.vue'
import IconBellOutline from 'vue-material-design-icons/BellOutline.vue'
import IconChevronDown from 'vue-material-design-icons/ChevronDown.vue'
import IconClose from 'vue-material-design-icons/Close.vue'
import IconMessageOutline from 'vue-material-design-icons/MessageOutline.vue'
import IconNotification from './Components/IconNotification.vue'
import NotificationItem from './Components/NotificationItem.vue'
import {
	getNotificationsData,
	setCurrentTabAsActive,
} from './services/notificationsService.js'
import { createWebNotification } from './services/webNotificationsService.js'
import {
	setWebPush,
} from './services/webPushService.js'

const sessionKeepAlive = loadState('core', 'config', { session_keepalive: true }).session_keepalive
const hasThrottledPushNotifications = loadState('notifications', 'throttled_push_notifications')
const webPushForBrowsersEnabled = getCapabilities()?.notifications?.push?.includes('webpush-browsers')

const fairUsePolicyNotification = {
	// Required properties
	notificationId: -1,
	app: 'core',
	user: '',
	datetime: 'warning',
	objectId: '',
	objectType: '',
	subject: t('notifications', 'Push notifications might be unreliable'),
	message: t('notifications', 'Nextcloud GmbH sponsors a free push notification gateway for private users. To ensure good service, the gateway limits the number of push notifications per server. For enterprise users, a more scalable gateway is available. Contact Nextcloud GmbH for more information.'),
	link: 'https://nextcloud.com/fairusepolicy',
	actions: [],
	// Optional properties
	externalLink: 'https://nextcloud.com/fairusepolicy',
	icon: imagePath('core', 'actions/alert-outline.svg'),
}

export default {
	name: 'NotificationsApp',

	components: {
		IconBellOff,
		IconBellOutline,
		IconChevronDown,
		IconClose,
		IconMessageOutline,
		IconNotification,
		NcButton,
		NcEmptyContent,
		NcHeaderMenu,
		NotificationItem,
	},

	setup() {
		return {
			fairUsePolicyNotification,
			hasThrottledPushNotifications,
		}
	},

	data() {
		return {
			webNotificationsGranted: false,
			backgroundFetching: false,
			hasNotifyPush: false,
			shutdown: false,
			notifications: [],
			lastETag: null,
			lastTabId: null,
			userStatus: null,
			tabId: null,

			/**
			 * Notifications older than this ID will not do a web notification.
			 *
			 * Sometimes a notification got "newly mounted" while being old.
			 * This can happen when a user has many notifications (100-1).
			 * The UI first only loads (100-76), if any notification is then
			 * resolved (e.g. by deleting or reading a chat), further old
			 * notifications (75+74) would be added to the UI and triggered
			 * a web notification (including call sound) in the past.
			 *
			 * This threshold ID is therefore updated to only higher values,
			 * before each pulling of notifications to ensure that we only ever
			 * web-notify on new notifications and not newly loaded old
			 * notifications.
			 */
			webNotificationsThresholdId: 0,

			/** @type {number} */
			pollIntervalBase: 30000, // milliseconds
			/** @type {number} */
			pollIntervalCurrent: 30000, // milliseconds

			/** @type {number|null} */
			interval: null,
			pushEndpoints: null,

			open: false,

		/** Highest notification ID seen when the popup was last opened; items above this are "new" */
		lastOpenMaxId: 0,
		/** Set of app names whose group is currently collapsed */
		collapsedGroups: new Set(),

		/** Whether Do Not Disturb is enabled locally (suppresses badge, sounds, browser notifications) */
		isDnd: JSON.parse(localStorage.getItem('notifications:dnd') ?? 'false'),
		/** Map of notificationId → timestamp when the snooze expires */
		snoozed: JSON.parse(localStorage.getItem('notifications:snoozed') ?? '{}'),
		/** Active filter tab: 'all' | 'mentions' | 'files' | 'other' */
		activeFilter: 'all',
		/** Pending optimistic dismiss: { notification, execute, timerId, collapseTimerId } */
		pendingUndo: null,
		/** Set of notification IDs currently playing collapse animation */
		collapsingIds: new Set(),
		/** Count of notifications that arrived while DND was on (> 0 shows banner) */
		dndBanner: 0,
		/** True for 2.5 s after all notifications are cleared — inbox zero celebration */
		showInboxZero: false,
		}
	},

	computed: {
		showBrowserNotifications() {
			return this.backgroundFetching
				&& this.webNotificationsGranted
				&& this.userStatus !== 'dnd'
				&& !this.isDnd
				&& this.tabId === this.lastTabId
		},

		emptyContentMessage() {
			if (this.webNotificationsGranted === null) {
				return t('notifications', 'Requesting browser permissions to show notifications')
			}
			if (this.hasThrottledPushNotifications) {
				return this.fairUsePolicyNotification.subject
			}
			if (this.activeFilter !== 'all' && this.notifications.length > 0) {
				return t('notifications', 'No notifications in this category')
			}
			return t('notifications', 'No notifications')
		},

		emptyContentDescription() {
			if (this.hasThrottledPushNotifications) {
				return this.fairUsePolicyNotification.message
			}

			return ''
		},

		notificationGroups() {
			const now = Date.now()
			const groups = new Map()
			for (const n of this.notifications) {
				if ((this.snoozed[n.notificationId] ?? 0) > now) continue
				if (this.activeFilter === 'mentions' && n.objectType !== 'mention') continue
				if (this.activeFilter === 'files' && !['files', 'files_sharing'].includes(n.app)) continue
				if (this.activeFilter === 'other' && (n.objectType === 'mention' || ['files', 'files_sharing'].includes(n.app))) continue
				if (!groups.has(n.app)) groups.set(n.app, [])
				groups.get(n.app).push(n)
			}
			return [...groups.entries()].map(([app, items]) => ({ app, items }))
		},

		filterTabs() {
			const now = Date.now()
			const counts = { mentions: 0, files: 0, other: 0 }
			for (const n of this.notifications) {
				if ((this.snoozed[n.notificationId] ?? 0) > now) continue
				if (n.objectType === 'mention') counts.mentions++
				else if (['files', 'files_sharing'].includes(n.app)) counts.files++
				else counts.other++
			}
			const tabs = [{ id: 'all', label: t('notifications', 'All') }]
			if (counts.mentions) tabs.push({ id: 'mentions', label: t('notifications', 'Mentions'), count: counts.mentions })
			if (counts.files) tabs.push({ id: 'files', label: t('notifications', 'Files'), count: counts.files })
			if (counts.other) tabs.push({ id: 'other', label: t('notifications', 'Other'), count: counts.other })
			return tabs
		},

		showFilterTabs() {
			return this.filterTabs.length > 2
		},

		dndBannerText() {
			const c = this.dndBanner
			return c === 1
				? t('notifications', '1 new notification received while in Do Not Disturb')
				: t('notifications', '{count} new notifications received while in Do Not Disturb', { count: c })
		},
	},

	watch: {
		notificationGroups(groups) {
			if (groups.length === 0 && this.activeFilter !== 'all') {
				this.activeFilter = 'all'
			}
		},
		'notifications.length'(newLen, oldLen) {
			if (newLen === 0 && oldLen > 0) {
				this.showInboxZero = true
				setTimeout(() => { this.showInboxZero = false }, 2500)
			}
		},
	},

	mounted() {
		this.tabId = getRequestToken() || ('' + Math.random())
		this._oldcount = 0

		this.checkWebNotificationPermissions()

		// Initial call to the notification endpoint
		this._fetch()

		const hasPush = listen('notify_notification', () => {
			this._fetchAfterNotifyPush()
		})
		if (hasPush) {
			console.debug('Has notify_push enabled, slowing polling to 15 minutes')
			this.pollIntervalBase = 15 * 60 * 1000
			this.hasNotifyPush = true
		}

		// set the polling interval after checking web push status
		// if web push may be configured
		if (webPushForBrowsersEnabled && this.webNotificationsGranted === true) {
			// We don't fetch on push if notify_push is enabled, to avoid concurrency fetch.
			// We could do the other way: fallback to notify_push only if we don't have
			// web push
			window.addEventListener('load', () => {
				this._setWebPush()
			})
		} else {
			// Set up the background checker
			this._setPollingInterval(this.pollIntervalBase)
		}

		this._watchTabVisibility()
		subscribe('networkOffline', this.handleNetworkOffline)
		subscribe('networkOnline', this.handleNetworkOnline)
		subscribe('user_status:status.updated', this.userStatusUpdated)
	},

	beforeUnmount() {
		unsubscribe('user_status:status.updated', this.userStatusUpdated)
		unsubscribe('networkOffline', this.handleNetworkOffline)
		unsubscribe('networkOnline', this.handleNetworkOnline)
	},

	methods: {
		t,

		userStatusUpdated(state) {
			if (getCurrentUser().uid === state.userId) {
				this.userStatus = state.status
			}
		},

		async _setWebPush() {
			return setWebPush(
				// onActivated=
				(hasWebPush) => {
					if (hasWebPush) {
						console.debug('Has web push, slowing polling to 15 minutes')
						this.pollIntervalBase = 15 * 60 * 1000
						this.hasNotifyPush = true
					}
					// Set polling interval for the default or new value
					this._setPollingInterval(this.pollIntervalBase)
				},
				// onPush=
				() => {
					if (!this.hasNotifyPush) {
						this._fetchAfterWebPush()
					} else {
						console.debug('Has notify_push, no need to fetch from web push.')
					}
				},
			)
		},

		async onOpen() {
			// Capture the current max ID before fetching so any newly arrived items are marked "new"
			this.lastOpenMaxId = this.notifications.reduce((max, n) => Math.max(max, n.notificationId), 0)

			if (this.webNotificationsGranted === null) {
				this.requestWebNotificationPermissions()
					.then((granted) => {
						if (granted && webPushForBrowsersEnabled) {
							this._setWebPush()
						}
					})
			}

			await setCurrentTabAsActive(this.tabId)
			await this._fetch()
		},

		handleNetworkOffline() {
			console.debug('Network is offline, slowing down pollingInterval to ' + this.pollIntervalBase * 10)
			this._setPollingInterval(this.pollIntervalBase * 10)
		},

		handleNetworkOnline() {
			this._fetch()
			console.debug('Network is online, reseting pollingInterval to ' + this.pollIntervalBase)
			this._setPollingInterval(this.pollIntervalBase)
		},

		setupBackgroundFetcher() {
			if (sessionKeepAlive) {
				console.debug('Started background fetcher as session_keepalive is enabled')
				this.interval = window.setInterval(this._backgroundFetch.bind(this), this.pollIntervalCurrent)
			} else {
				console.debug('Did not start background fetcher as session_keepalive is off')
			}
		},

		onDismissAll() {
			axios
				.delete(generateOcsUrl('apps/notifications/api/v2/notifications'))
				.then(() => {
					this.notifications = []
					this.open = false
					setCurrentTabAsActive(this.tabId)
				})
				.catch(() => {
					showError(t('notifications', 'Failed to dismiss all notifications'))
				})
		},

		onRemove(notification) {
			const idx = this.notifications.findIndex(n => n.notificationId === notification.notificationId)
			if (idx !== -1) {
				this.notifications.splice(idx, 1)
			}
			setCurrentTabAsActive(this.tabId)
		},

		async onDismiss(notification) {
			// Flush any prior pending dismiss immediately
			if (this.pendingUndo) {
				clearTimeout(this.pendingUndo.timerId)
				clearTimeout(this.pendingUndo.collapseTimerId)
				const prevIdx = this.notifications.findIndex(n => n.notificationId === this.pendingUndo.notification.notificationId)
				if (prevIdx !== -1) this.notifications.splice(prevIdx, 1)
				this.collapsingIds.delete(this.pendingUndo.notification.notificationId)
				await this.pendingUndo.execute()
			}

			setCurrentTabAsActive(this.tabId)

			// Trigger collapse animation — item stays in array until animation finishes (280 ms)
			this.collapsingIds.add(notification.notificationId)

			const execute = () => axios
				.delete(generateOcsUrl('apps/notifications/api/v2/notifications/{id}', { id: notification.notificationId }))
				.catch(() => showError(t('notifications', 'Failed to dismiss notification')))

			const collapseTimerId = setTimeout(() => {
				const idx = this.notifications.findIndex(n => n.notificationId === notification.notificationId)
				if (idx !== -1) this.notifications.splice(idx, 1)
				this.collapsingIds.delete(notification.notificationId)
			}, 280)

			this.pendingUndo = {
				notification,
				execute,
				collapseTimerId,
				timerId: setTimeout(() => {
					this.pendingUndo = null
					execute()
				}, 4000),
			}
		},

		onUndoDismiss() {
			if (!this.pendingUndo) return
			clearTimeout(this.pendingUndo.timerId)
			clearTimeout(this.pendingUndo.collapseTimerId)
			const { notification } = this.pendingUndo
			this.pendingUndo = null
			// Stop collapse animation
			this.collapsingIds.delete(notification.notificationId)
			// Re-insert if the collapse timer already removed it from the array
			if (!this.notifications.find(n => n.notificationId === notification.notificationId)) {
				const insertIdx = this.notifications.findIndex(n => n.notificationId < notification.notificationId)
				if (insertIdx === -1) this.notifications.push(notification)
				else this.notifications.splice(insertIdx, 0, notification)
			}
			setCurrentTabAsActive(this.tabId)
		},

		toggleDnd() {
			if (!this.isDnd) {
				// Turning ON: snapshot current max ID so we can count new arrivals on re-enable
				this._dndMaxIdAtEnable = this.notifications.reduce((max, n) => Math.max(max, n.notificationId), 0)
			} else {
				// Turning OFF: surface a banner for any notifications that arrived while DND was active
				const newCount = this.notifications.filter(n => n.notificationId > (this._dndMaxIdAtEnable || 0)).length
				if (newCount > 0) this.dndBanner = newCount
			}
			this.isDnd = !this.isDnd
			localStorage.setItem('notifications:dnd', JSON.stringify(this.isDnd))
		},

		onSnooze({ notification, minutes }) {
			const wakeAt = Date.now() + minutes * 60 * 1000
			this.snoozed = { ...this.snoozed, [notification.notificationId]: wakeAt }
			localStorage.setItem('notifications:snoozed', JSON.stringify(this.snoozed))
		},

		_clearExpiredSnooze() {
			const now = Date.now()
			const active = Object.fromEntries(
				Object.entries(this.snoozed).filter(([, wakeAt]) => wakeAt > now),
			)
			if (Object.keys(active).length !== Object.keys(this.snoozed).length) {
				this.snoozed = active
				localStorage.setItem('notifications:snoozed', JSON.stringify(active))
			}
		},

		formatAppName(app) {
			return app.replace(/_/g, ' ').replace(/\b\w/g, c => c.toUpperCase())
		},

		toggleGroup(app) {
			if (this.collapsedGroups.has(app)) {
				this.collapsedGroups.delete(app)
			} else {
				this.collapsedGroups.add(app)
			}
		},

		visibleIndex(groupIdx, itemIdx) {
			let idx = 0
			for (let g = 0; g < groupIdx; g++) {
				idx += this.notificationGroups[g].items.length
			}
			return idx + itemIdx
		},

		/**
		 * Update the title to show * if there are new notifications
		 *
		 * @param {object} notifications The list of notifications
		 */
		_updateDocTitleOnNewNotifications(notifications) {
			if (notifications.length > this._oldcount) {
				this._oldcount = notifications.length
				if (this.backgroundFetching && document.hidden) {
					// If we didn't already highlight, store the title so we can restore on tab-view
					if (!document.title.startsWith('* ')) {
						document.title = '* ' + document.title
					}
				}
			}
		},

		/**
		 * Restore the title to remove a *
		 * Only restore title if it's still what we set it to,
		 * the Talk might have altered it.
		 */
		_restoreTitle() {
			if (document.title.startsWith('* ')) {
				document.title = document.title.substring(2)
			}
		},

		/**
		 * Performs the AJAX request to retrieve the notifications
		 */
		_fetchAfterNotifyPush() {
			this.backgroundFetching = true
			if (this.hasNotifyPush && this.tabId !== this.lastTabId) {
				console.debug('Deferring notification refresh from browser storage are notify_push event to give the last tab the chance to do it')
				setTimeout(() => {
					this._fetch()
				}, 5000)
			} else {
				console.debug('Refreshing notifications are notify_push event')
				this._fetch()
			}
		},

		/**
		 * Performs the AJAX request to retrieve the notifications
		 *
		 * Unlike with notify_push, we don't have to check if we are the last tab before
		 * fetching events. The service worker sends the event to only one tab, that may
		 * not be the last one
		 */
		_fetchAfterWebPush() {
			this.backgroundFetching = true
			console.debug('Refreshing notifications following web push event')
			this._fetch(true)
		},

		/**
		 * Performs the AJAX request to retrieve the notifications
		 */
		async _fetch(force = false) {
			this._clearExpiredSnooze()

			if (this.notifications.length && this.notifications[0].notificationId > this.webNotificationsThresholdId) {
				this.webNotificationsThresholdId = this.notifications[0].notificationId
			}

			const response = await getNotificationsData(this.tabId, this.lastETag, force || !this.backgroundFetching, this.hasNotifyPush)

			if (response.status === 204) {
				// 204 No Content - Intercept when no notifiers are there.
				console.debug('Fetching notifications but no content, slowing down polling to ' + this.pollIntervalBase * 10)
				this._setPollingInterval(this.pollIntervalBase * 10)
			} else if (response.status === 200) {
				this.userStatus = response.headers['x-nextcloud-user-status']
				this.lastETag = response.headers.etag
				this.lastTabId = response.tabId
				// Keep the pending-undo item out of the list during its grace period
				const pendingId = this.pendingUndo?.notification?.notificationId
				const data = pendingId
					? response.data.filter(n => n.notificationId !== pendingId)
					: response.data
				this.notifications = data
				this.processWebNotifications(data)
				console.debug('Got notification data, restoring default polling interval.')
				this._setPollingInterval(this.pollIntervalBase)
				this._updateDocTitleOnNewNotifications(this.notifications)

				if (!this.backgroundFetching && this.notifications.length) {
					this.webNotificationsThresholdId = this.notifications[0].notificationId
				}
			} else if (response.status === 304) {
				// 304 - Not modified
				this._setPollingInterval(this.pollIntervalBase)
			} else if (response.status === 503) {
				// 503 - Maintenance mode
				console.info('Slowing down notifications: instance is in maintenance mode.')
				this._setPollingInterval(this.pollIntervalBase * 10)
			} else if (response.status === 404) {
				// 404 - App disabled
				console.info('Slowing down notifications: app is disabled.')
				this._setPollingInterval(this.pollIntervalBase * 10)
			} else {
				console.info('Slowing down notifications: Status ' + response.status)
				this._setPollingInterval(this.pollIntervalBase * 10)
			}
		},

		_backgroundFetch() {
			this.backgroundFetching = true
			this._fetch()
		},

		_watchTabVisibility() {
			document.addEventListener('visibilitychange', this._visibilityChange, false)
		},

		_visibilityChange() {
			if (!document.hidden) {
				this._restoreTitle()
			}
		},

		_setPollingInterval(pollInterval) {
			if (this.interval && pollInterval === this.pollIntervalCurrent) {
				return
			}

			console.debug('Polling interval updated to ' + pollInterval)

			if (this.interval) {
				window.clearInterval(this.interval)
				this.interval = null
			}

			this.pollIntervalCurrent = pollInterval
			this.setupBackgroundFetcher()
		},

		/**
		 * The app was disabled or has no notifiers, so we can stop polling
		 * And hide the UI as well
		 *
		 * @param {boolean} temporary If false, the notification bell will be hidden
		 */
		_shutDownNotifications(temporary) {
			console.debug('Shutting down notifications ' + ((temporary) ? 'temporary' : 'bye'))
			if (this.interval) {
				window.clearInterval(this.interval)
				this.interval = null
			}
			this.shutdown = !temporary
		},

		/**
		 * Check if we can do web notifications
		 */
		checkWebNotificationPermissions() {
			if (!('Notification' in window)) {
				console.info('Browser does not support notifications')
				this.webNotificationsGranted = false
				return
			}

			if (window.Notification.permission === 'granted') {
				console.debug('Notifications permissions granted')
				this.webNotificationsGranted = true
				return
			}

			if (window.Notification.permission === 'denied') {
				console.debug('Notifications permissions denied')
				this.webNotificationsGranted = false
				return
			}

			if (!window.isSecureContext) {
				console.debug('Notifications require HTTPS')
				this.webNotificationsGranted = false
				return
			}

			console.info('Notifications permissions not yet requested')
			this.webNotificationsGranted = null
		},

		/**
		 * Check if we can do web notifications
		 */
		async requestWebNotificationPermissions() {
			if (this.webNotificationsGranted !== null) {
				return new Promise((resolve) => resolve(this.webNotificationsGranted))
			}

			console.info('Requesting notifications permissions')
			return window.Notification.requestPermission()
				.then((permissions) => {
					return this.webNotificationsGranted = permissions === 'granted'
				})
		},

		processWebNotifications(notifications) {
			notifications.forEach((notification) => {
				if (this.backgroundFetching) {
					// Can not rely on showBrowserNotifications because each tab should
					// be able to utilize the data from the notification in events.
					const event = { notification }
					emit('notifications:notification:received', event)
				}

				if (this.showBrowserNotifications && this.webNotificationsThresholdId < notification.notificationId) {
					createWebNotification(notification)
				}
			})
		},
	},
}
</script>

